Ah, I see. Try wrapping the conditional view in a `withAnimation` block directly in the ErrorToastController when setting the message. This should ensure the animation runs when the toast appears.

Here's how to modify your ErrorToastController:

```swift
class ErrorToastController: ObservableObject {
    @Published private(set) var message: (text: String, duration: TimeInterval)?

    func show(message: String, duration: TimeInterval = 2.0) {
        withAnimation {
            self.message = (message, duration)
        }
    }

    func dismiss() {
        withAnimation {
            message = nil
        }
    }
}
```

